import React, { useEffect, useState } from 'react';
import { streamxApi } from '../services/api';

export default function ReelsPage() {
  const [reels, setReels] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    streamxApi.getMovieReels()
      .then((res) => setReels(res.data || []))
      .catch(() => setReels([]))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return <main style={{ paddingTop: '96px', padding: '96px 24px 24px' }}>Loading reels...</main>;
  }

  return (
    <main style={{ paddingTop: '96px', padding: '96px 24px 24px' }}>
      <h1 style={{ marginBottom: '16px' }}>Movie Reels</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '16px' }}>
        {reels.map((item) => (
          <article key={item.id} style={{ background: '#111', border: '1px solid #2a2a2a', borderRadius: '12px', overflow: 'hidden' }}>
            {item.poster && <img src={item.poster} alt={item.title} style={{ width: '100%', height: '280px', objectFit: 'cover' }} />}
            <div style={{ padding: '12px' }}>
              <h3 style={{ margin: '0 0 6px 0' }}>{item.title}</h3>
              <p style={{ margin: 0, color: '#b5b5b5', fontSize: '0.9rem' }}>{item.year} • {item.genre}</p>
            </div>
          </article>
        ))}
      </div>
    </main>
  );
}
